<template>
  <div class="quiz-container">
    <!-- Прогресс бар -->
    <div class="progress-bar-container">
      <div class="progress-bar" :style="{ width: progressPercentage + '%' }"></div>
    </div>

    <!-- Вопрос -->
    <div class="question-container">
      <h2 class="h2 white-text montserrat-bold question-title">
        {{ currentQuestion.question }}
      </h2>

      <!-- Варианты ответов -->
      <div class="answers-grid">
        <button
          v-for="answer in currentQuestion.answers"
          :key="answer.value"
          @click="selectAnswer(answer.value)"
          class="answer-button montserrat-medium p"
        >
          {{ answer.label }}
        </button>
      </div>

      <!-- Счётчик вопросов -->
      <p class="p-small gray-text montserrat-regular question-counter">
        Вопрос {{ currentQuestionIndex + 1 }} из {{ questions.length }}
      </p>
    </div>

    <!-- Результат -->
    <div v-if="isCompleted" class="result-container">
      <h2 class="h2 gradient-second-text montserrat-bold">
        Спасибо за ответы!
      </h2>
      <p class="p white-text montserrat-regular">
        Подбираем идеальный подарок для вас...
      </p>
      <button @click="resetQuiz" class="button-second montserrat-medium p">
        Пройти заново
      </button>
    </div>
  </div>
</template>

<script>
export default {
  name: 'GiftQuiz',
  data() {
    return {
      currentQuestionIndex: 0,
      answers: [],
      isCompleted: false,
      questions: [
        {
          question: 'Кому вы выбираете подарок?',
          answers: [
            { label: 'Мужчине', value: 'male' },
            { label: 'Женщине', value: 'female' },
            { label: 'Ребёнку', value: 'child' }
          ]
        },
        {
          question: 'Какой возраст получателя?',
          answers: [
            { label: 'До 18 лет', value: 'young' },
            { label: '18-35 лет', value: 'adult' },
            { label: '35-55 лет', value: 'middle' },
            { label: '55+ лет', value: 'senior' }
          ]
        },
        {
          question: 'У получателя есть автомобиль?',
          answers: [
            { label: 'Да', value: 'yes' },
            { label: 'Нет', value: 'no' }
          ]
        },
        {
          question: 'Есть ли домашние животные?',
          answers: [
            { label: 'Да, есть', value: 'yes' },
            { label: 'Нет', value: 'no' }
          ]
        },
        {
          question: 'Какое увлечение ближе?',
          answers: [
            { label: 'Спорт', value: 'sport' },
            { label: 'Творчество', value: 'creative' },
            { label: 'Технологии', value: 'tech' },
            { label: 'Кулинария', value: 'cooking' }
          ]
        },
        {
          question: 'Предпочитает проводить время:',
          answers: [
            { label: 'Дома', value: 'home' },
            { label: 'На природе', value: 'outdoor' },
            { label: 'В путешествиях', value: 'travel' }
          ]
        },
        {
          question: 'Стиль жизни:',
          answers: [
            { label: 'Активный', value: 'active' },
            { label: 'Спокойный', value: 'calm' },
            { label: 'Смешанный', value: 'mixed' }
          ]
        },
        {
          question: 'Бюджет на подарок:',
          answers: [
            { label: 'До 2000 ₽', value: 'low' },
            { label: '2000-5000 ₽', value: 'medium' },
            { label: '5000-10000 ₽', value: 'high' },
            { label: 'Более 10000 ₽', value: 'premium' }
          ]
        },
        {
          question: 'Повод для подарка:',
          answers: [
            { label: 'День рождения', value: 'birthday' },
            { label: 'Новый год', value: 'newyear' },
            { label: 'Годовщина', value: 'anniversary' },
            { label: 'Просто так', value: 'just' }
          ]
        },
        {
          question: 'Что важнее в подарке?',
          answers: [
            { label: 'Практичность', value: 'practical' },
            { label: 'Эмоции', value: 'emotional' },
            { label: 'Оригинальность', value: 'unique' }
          ]
        }
      ]
    }
  },
  computed: {
    currentQuestion() {
      return this.questions[this.currentQuestionIndex]
    },
    progressPercentage() {
      return ((this.currentQuestionIndex + 1) / this.questions.length) * 100
    }
  },
  methods: {
    selectAnswer(value) {
      this.answers.push({
        questionIndex: this.currentQuestionIndex,
        answer: value
      })

      if (this.currentQuestionIndex < this.questions.length - 1) {
        this.currentQuestionIndex++
      } else {
        this.completeQuiz()
      }
    },
    completeQuiz() {
      this.isCompleted = true
      console.log('Результаты опроса:', this.answers)
      // Здесь можно отправить данные на сервер или обработать их
    },
    resetQuiz() {
      this.currentQuestionIndex = 0
      this.answers = []
      this.isCompleted = false
    }
  }
}
</script>

