            placeholder="От"
            class="price-input montserrat-regular"
          />
          <span class="gray-text">—</span>
          <input 
            v-model.number="priceRange.max"
            type="number"
            placeholder="До"
            class="price-input montserrat-regular"
          />
        </div>
      </div>

