      <div class="filter-group">
        <h3 class="p montserrat-semibold white-text">Категории</h3>
        <div class="tags-list">
          <label 
            v-for="tag in availableTags" 
            :key="tag"
            class="tag-checkbox montserrat-regular"
          >
            <input 
              type="checkbox" 
              :value="tag"
              v-model="selectedTags"
            />
            <span>{{ tag }}</span>
          </label>
        </div>
      </div>

      <!-- Сортировка -->
      <div class="filter-group">
        <h3 class="p montserrat-semibold white-text">Сортировка</h3>
        <select v-model="sortBy" class="sort-select montserrat-regular">
          <option value="default">По умолчанию</option>
          <option value="price-asc">Цена: по возрастанию</option>
          <option value="price-desc">Цена: по убыванию</option>
        </select>
      </div>

      <!-- Кнопка сброса -->
      <button 
        v-if="activeFiltersCount > 0"
        @click="resetFilters"
        class="reset-btn montserrat-medium"
      >
        Сбросить фильтры
      </button>
    </div>

    <!-- Результаты -->
    <div class="results-info montserrat-regular gray-text">
      Найдено боксов: {{ filteredBoxes.length }}
    </div>

    <!-- Сетка карточек -->
    <div class="cards-wrapper">
      <Card 
        v-for="box in displayedBoxes" 
        :key="box.id"
        :box="box"
      />
    </div>

    <!-- Кнопка "Показать ещё" -->
    <div v-if="hasMore" class="load-more-container">
      <button 
        @click="loadMore"
        class="load-more-btn montserrat-semibold"
      >
        Показать ещё
      </button>
    </div>

    <!-- Пустое состояние -->
    <div v-if="filteredBoxes.length === 0" class="empty-state">
      <p class="p montserrat-regular gray-text">
        По вашему запросу ничего не найдено 😔
      </p>
      <button @click="resetFilters" class="button-second montserrat-semibold">
        Сбросить фильтры
      </button>
    </div>
