<script setup>
import { ref, computed, onMounted } from 'vue'
import Card from '@/components/Card.vue'
import { boxes, calculateBoxPrice, getShortComposition } from '@/data/boxes'

// Состояние
const searchQuery = ref('')
const showFilters = ref(false)
const priceRange = ref({ min: null, max: null })
const selectedTags = ref([])
const sortBy = ref('default')
const itemsPerPage = 16
const currentPage = ref(1)

// Все доступные теги
const availableTags = computed(() => {
  const tags = new Set()
  boxes.forEach(box => {
    box.tags.forEach(tag => tags.add(tag))
  })
  return Array.from(tags).sort()
})

// Количество активных фильтров
const activeFiltersCount = computed(() => {
  let count = 0
  if (searchQuery.value) count++
  if (priceRange.value.min || priceRange.value.max) count++
  if (selectedTags.value.length > 0) count++
  if (sortBy.value !== 'default') count++
  return count
})

// Фильтрация и сортировка
const filteredBoxes = computed(() => {
  let result = [...boxes]

  // Поиск по названию
  if (searchQuery.value) {
    const query = searchQuery.value.toLowerCase()
    result = result.filter(box => 
      box.name.toLowerCase().includes(query) ||
      box.tagline.toLowerCase().includes(query)
    )
  }

  // Фильтр по цене
  if (priceRange.value.min || priceRange.value.max) {
    result = result.filter(box => {
      const price = calculateBoxPrice(box.id)
      const minOk = !priceRange.value.min || price >= priceRange.value.min
      const maxOk = !priceRange.value.max || price <= priceRange.value.max
      return minOk && maxOk
    })
  }

  // Фильтр по тегам (любой из выбранных)
  if (selectedTags.value.length > 0) {
    result = result.filter(box =>
      box.tags.some(tag => selectedTags.value.includes(tag))
    )
  }

  // Сортировка
  if (sortBy.value === 'price-asc') {
    result.sort((a, b) => calculateBoxPrice(a.id) - calculateBoxPrice(b.id))
  } else if (sortBy.value === 'price-desc') {
    result.sort((a, b) => calculateBoxPrice(b.id) - calculateBoxPrice(a.id))
  }

  return result
})

// Отображаемые боксы (с пагинацией)
const displayedBoxes = computed(() => {
  return filteredBoxes.value.slice(0, currentPage.value * itemsPerPage)
})

// Есть ли ещё боксы
const hasMore = computed(() => {
  return displayedBoxes.value.length < filteredBoxes.value.length
})

// Загрузить ещё
function loadMore() {
  currentPage.value++
}

// Сбросить фильтры
function resetFilters() {
  searchQuery.value = ''
  priceRange.value = { min: null, max: null }
  selectedTags.value = []
  sortBy.value = 'default'
  currentPage.value = 1
}

// Сбросить пагинацию при изменении фильтров
import { watch } from 'vue'
watch([searchQuery, priceRange, selectedTags, sortBy], () => {
  currentPage.value = 1
}, { deep: true })
</script>

